<?php if(!hasPermission('sales_read')){http_response_code(403); include __DIR__.'/../errors/403.php'; return;} $db=Database::connection(); $id=(int)($segments[2]??0); $h=$db->prepare('SELECT s.*,c.name customer FROM sales_invoices s LEFT JOIN customers c ON c.id=s.customer_id WHERE s.id=?');$h->execute([$id]);$s=$h->fetch(); $i=$db->prepare('SELECT * FROM sales_items WHERE sales_id=?');$i->execute([$id]);$items=$i->fetchAll(); ?><div class='container py-4'><h3>Sales <?=sanitize($s['invoice_no']??'')?></h3><a href='<?=url('sales/payment/'.$id)?>'>Payment</a> <a href='<?=url('sales/print/'.$id)?>'>Print</a><table class='table'><?php foreach($items as $r):?><tr><td><?=sanitize($r['product_type'])?></td><td><?=$r['quantity']?></td><td><?=$r['total_amount']?></td></tr><?php endforeach;?></table></div>
